sql:
SELECT COUNT(*) AS total_downloads
FROM downloads
WHERE version_id = 1;

SELECT app_name, developer_name
FROM applications
INNER JOIN developers ON applications.developer_id = developers.developer_id;

SELECT download_date
FROM downloads
ORDER BY download_date DESC;

SELECT version_id, download_count
FROM versions
ORDER BY download_count DESC;

SELECT * 
FROM versions 
WHERE file_size > 50;

SELECT app_id, MAX(update_at) as latest_update
FROM versions
GROUP BY app_id;

SELECT version_id, file_size
FROM versions
ORDER BY file_size DESC;

SELECT download_id, version_id, user_id, download_date
FROM downloads
WHERE download_date > '2023-02-01 00:00:00';

SELECT user_id, COUNT(download_id) AS total_downloads
FROM downloads
GROUP BY user_id;
